#include <stdio.h>
#include <stdlib.h>

int countUniquePaths(int** grid, int gridSize, int gridColSize) {
    int** dp = (int**)malloc(gridSize * sizeof(int*));
    for (int i = 0; i < gridSize; i++) {
        dp[i] = (int*)malloc(gridColSize * sizeof(int));
    }

    if (grid[0][0] == 0) {
        dp[0][0] = 1;
    } else {
        dp[0][0] = 0;
    }

    for (int i = 1; i < gridColSize; i++) {
        if (grid[0][i] == 0) {
            dp[0][i] = dp[0][i-1];
        } else {
            dp[0][i] = 0;
        }
    }

    for (int i = 1; i < gridSize; i++) {
        if (grid[i][0] == 0) {
            dp[i][0] = dp[i-1][0];
        } else {
            dp[i][0] = 0;
        }
    }

    for (int i = 1; i < gridSize; i++) {
        for (int j = 1; j < gridColSize; j++) {
            if (grid[i][j] == 0) {
                dp[i][j] = dp[i-1][j] + dp[i][j-1];
            } else {
                dp[i][j] = 0;
            }
        }
    }

    int result = dp[gridSize-1][gridColSize-1];
    for (int i = 0; i < gridSize; i++) {
        free(dp[i]);
    }
    free(dp);
    return result;
}

