def countUniquePaths(grid):
    rows, cols = len(grid), len(grid[0])
    dp = [[0]*cols for _ in range(rows)]

    if grid[0][0] == 0:
        dp[0][0] = 1

    for i in range(1, cols):
        if grid[0][i] == 0:
            dp[0][i] = dp[0][i-1]

    for i in range(1, rows):
        if grid[i][0] == 0:
            dp[i][0] = dp[i-1][0]

    for i in range(1, rows):
        for j in range(1, cols):
            if grid[i][j] == 0:
                dp[i][j] = dp[i-1][j] + dp[i][j-1]

    return dp[-1][-1]

